const v = msg.payload || {};
if (!msg.payload || typeof msg.payload !== 'object') return null;

// Sample at most once per minute
const now = Date.now();
const lastMs = global.get('trendPowerLastMs') || 0;
if (now - lastMs < 60_000) return null;
global.set('trendPowerLastMs', now);

const toNum = (x) => {
  const n = typeof x === 'number' ? x : Number(x);
  return Number.isFinite(n) ? n : 0;
};

const meterPrefixes = [
  'RIO1CM1_EMU4_1', 'RIO1CM1_EMU4_2',
  'RIO1CM2_EM6400_10', 'RIO1CM2_EM6400_11',
  'RIO2CM1_EMU4_1', 'RIO2CM1_EMU4_2', 'RIO2CM1_EMU4_3', 'RIO2CM1_EMU4_4',
  'RIO2CM1_EMU4_5', 'RIO2CM1_EMU4_6', 'RIO2CM1_EMU4_7', 'RIO2CM1_EMU4_8',
  'RIO2CM1_EMU4_9', 'RIO2CM1_EMU4_10', 'RIO2CM1_EMU4_11', 'RIO2CM1_EMU4_12',
  'RIO2CM2_EM6400_1', 'RIO2CM2_EM6400_2', 'RIO2CM2_EM6400_3',
  'RIO2CM2_EM6400_4', 'RIO2CM2_EM6400_5', 'RIO2CM2_EM6400_6',
  'RIO2_PAC3200_51', 'RIO2_PAC3200_53', 'RIO2_UMG508_52'
];

let kvar = 0;
for (const p of meterPrefixes) {
  kvar += toNum(v[p + '_Reactive_power']);
}

const point = {
  ts: new Date().toISOString(),
  kw: toNum(v.Power_kW),
  voltageV: toNum(v.Voltage_V),
  currentA: toNum(v.Current_A),
  pf: toNum(v.PowerFactor),
  kvar
};

const arr = global.get('trendPower') || [];
arr.push(point);
// Keep last 7 days at 1/min (~10k points)
while (arr.length > 10_080) arr.shift();
global.set('trendPower', arr);

// ---- Record fluctuations into Enhanced Alerts (/api/alarms) ----
const pushAlert = (severity, priority, category, meterId, meterName, message, detail) => {
  const alerts = global.get('enhancedAlerts') || [];
  const ts = new Date().toISOString();

  const mId = meterId || 'plant';
  const mName = meterName || (mId === 'plant' ? 'Plant' : String(mId));

  // Dedupe: avoid spamming identical events every minute.
  const dedupeKey = `${mId}|${category}|${severity}|${message}`;
  const lastByKey = global.get('enhancedAlertsLastByKey') || {};
  const last = Number(lastByKey[dedupeKey] ?? 0);
  if (Number.isFinite(last) && (Date.now() - last) < 5 * 60_000) return;
  lastByKey[dedupeKey] = Date.now();
  global.set('enhancedAlertsLastByKey', lastByKey);

  const id = `evt-${ts}-${Math.random().toString(16).slice(2, 8)}`;
  alerts.unshift({
    id,
    meterId: mId,
    meterName: mName,
    severity,
    priority,
    category,
    status: 'active',
    message,
    detail,
    ts,
    acknowledgedAt: null,
    acknowledgedBy: null,
    resolvedAt: null,
    notes: [],
    incidentId: null
  });
  // keep recent 500
  while (alerts.length > 500) alerts.pop();
  global.set('enhancedAlerts', alerts);

  // Persist immediately so fluctuations are logged.
  try {
    const fs = global.get('fs');
    const p = global.get('alertsArchivePath');
    if (fs && p) fs.writeFileSync(p, JSON.stringify(global.get('enhancedAlerts') || [], null, 2), 'utf8');
  } catch (e) {}
};

const prev = global.get('trendPowerPrev') || null;
if (prev) {
  const pct = (cur, p) => (p !== 0 ? (cur - p) / Math.abs(p) : 0);
  const abs = (x) => Math.abs(x);

  const kwPct = abs(pct(point.kw, prev.kw));
  if (kwPct > 0.25) {
    const sev = kwPct > 0.4 ? 'critical' : 'warning';
    pushAlert(sev, sev === 'critical' ? 'high' : 'medium', 'energy', 'plant', 'Plant', `kW spike ${(kwPct * 100).toFixed(0)}%`, `kW changed from ${prev.kw.toFixed(2)} to ${point.kw.toFixed(2)} within ~1 minute.`);
  }

  const curPct = abs(pct(point.currentA, prev.currentA));
  if (curPct > 0.25) {
    const sev = curPct > 0.4 ? 'critical' : 'warning';
    pushAlert(sev, sev === 'critical' ? 'high' : 'medium', 'energy', 'plant', 'Plant', `Current surge ${(curPct * 100).toFixed(0)}%`, `Current changed from ${prev.currentA.toFixed(2)}A to ${point.currentA.toFixed(2)}A within ~1 minute.`);
  }

  // Voltage band based on rolling nominal (median of last 30 points)
  const recentV = arr.slice(-30).map((p) => p.voltageV).filter((x) => Number.isFinite(x) && x > 0);
  if (recentV.length >= 5) {
    const sorted = recentV.slice().sort((a,b)=>a-b);
    const mid = Math.floor(sorted.length / 2);
    const nominal = sorted.length % 2 === 1 ? sorted[mid] : (sorted[mid-1] + sorted[mid]) / 2;
    const off = abs((point.voltageV - nominal) / nominal);
    if (off > 0.05) {
      const sev = off > 0.10 ? 'critical' : 'warning';
      pushAlert(sev, sev === 'critical' ? 'high' : 'medium', 'power_quality', 'plant', 'Plant', `Voltage out of band ${(off * 100).toFixed(0)}%`, `Voltage ${point.voltageV.toFixed(2)}V vs nominal ${nominal.toFixed(2)}V.`);
    }
  }
}

// ---- Per-meter disconnect + fluctuations ----
const meterPrev = global.get('trendMeterPrev') || {};
const meterOnlinePrev = global.get('meterOnlinePrev') || {};
const meterVHist = global.get('trendMeterVHist') || {};

for (const m of meterPrefixes) {
  const kw = toNum(v[m + '_Real_power']);
  const volts = toNum(v[m + '_Voltage_Lave']);
  const amps = toNum(v[m + '_Current_Ave']);
  const pf = toNum(v[m + '_Power_factor']);

  const online = Number.isFinite(volts) && volts > 0;
  const prevOnline = meterOnlinePrev[m];
  if (prevOnline === undefined) {
    meterOnlinePrev[m] = online;
  } else if (prevOnline !== online) {
    meterOnlinePrev[m] = online;
    if (online) {
      pushAlert('info', 'low', 'communication', m, m, 'Meter communication restored', `Meter ${m} is reporting again.`);
    } else {
      pushAlert('critical', 'urgent', 'communication', m, m, 'Meter communication lost', `No voltage reading detected for meter ${m}.`);
    }
  }

  if (!online) continue;

  const vh = Array.isArray(meterVHist[m]) ? meterVHist[m] : [];
  vh.push(volts);
  while (vh.length > 30) vh.shift();
  meterVHist[m] = vh;

  const prevM = meterPrev[m];
  if (prevM) {
    const pct = (cur, p) => (p !== 0 ? (cur - p) / Math.abs(p) : 0);
    const abs = (x) => Math.abs(x);

    const kwPctM = abs(pct(kw, prevM.kw));
    if (kwPctM > 0.25) {
      const sev = kwPctM > 0.4 ? 'critical' : 'warning';
      pushAlert(sev, sev === 'critical' ? 'high' : 'medium', 'energy', m, m, `kW spike ${(kwPctM * 100).toFixed(0)}%`, `kW changed from ${Number(prevM.kw).toFixed(2)} to ${kw.toFixed(2)} within ~1 minute.`);
    }

    const ampsPctM = abs(pct(amps, prevM.amps));
    if (ampsPctM > 0.25) {
      const sev = ampsPctM > 0.4 ? 'critical' : 'warning';
      pushAlert(sev, sev === 'critical' ? 'high' : 'medium', 'energy', m, m, `Current surge ${(ampsPctM * 100).toFixed(0)}%`, `Current changed from ${Number(prevM.amps).toFixed(2)}A to ${amps.toFixed(2)}A within ~1 minute.`);
    }

    if (vh.length >= 5) {
      const sorted = vh.slice().sort((a,b)=>a-b);
      const mid = Math.floor(sorted.length / 2);
      const nominal = sorted.length % 2 === 1 ? sorted[mid] : (sorted[mid-1] + sorted[mid]) / 2;
      const off = abs((volts - nominal) / nominal);
      if (off > 0.05) {
        const sev = off > 0.10 ? 'critical' : 'warning';
        pushAlert(sev, sev === 'critical' ? 'high' : 'medium', 'power_quality', m, m, `Voltage out of band ${(off * 100).toFixed(0)}%`, `Voltage ${volts.toFixed(2)}V vs nominal ${nominal.toFixed(2)}V.`);
      }
    }
  }

  meterPrev[m] = { kw, amps, volts, pf, ts: point.ts };
}

global.set('trendMeterPrev', meterPrev);
global.set('meterOnlinePrev', meterOnlinePrev);
global.set('trendMeterVHist', meterVHist);

global.set('trendPowerPrev', point);
return null;

const minutes = Math.max(5, Math.min(60 * 24 * 7, Number(msg.req?.query?.minutes ?? 24 * 60)));
const since = Date.now() - minutes * 60 * 1000;
const arr = global.get('trendPower') || [];
msg.payload = arr.filter((p) => Date.parse(p.ts) >= since);
msg.headers = { 'Content-Type': 'application/json; charset=utf-8' };
return msg;

const minutes = Math.max(60, Math.min(60 * 24 * 366, Number(msg.req?.query?.minutes ?? 60 * 24 * 30)));
const sinceEpoch = Math.floor(Date.now() / 1000) - Math.floor(minutes * 60);

// Optional bucket override (seconds) to keep long windows lightweight.
// Accepts: bucketSec (number) or bucket ("1m"|"5m"|"15m"|"1h"|"1d").
const q = msg.req?.query ?? {};
const bucketMap = { '1m': 60, '5m': 300, '15m': 900, '1h': 3600, '1d': 86400 };
const parsedBucketSec = Number(q.bucketSec ?? q.bucket_sec);
const bucketToken = typeof q.bucket === 'string' ? q.bucket.trim().toLowerCase() : '';

// Default bucket size: finer for shorter windows so the curve looks continuous.
// - <= 31d: 1 minute
// - 32d–90d: 5 minutes
// - 91d–365d: 15 minutes
// - > 365d: 60 minutes
let bucketSec = 60;
if (minutes > 60 * 24 * 365) bucketSec = 3600;
else if (minutes > 60 * 24 * 90) bucketSec = 900;
else if (minutes > 60 * 24 * 31) bucketSec = 300;

// Enforce a max number of points to avoid browser OOM.
// Increase bucket size if the estimated number of buckets is too high.
const MAX_POINTS = 5000;
const estimate = Math.ceil((minutes * 60) / bucketSec);
if (estimate > MAX_POINTS) {
  const need = Math.ceil((minutes * 60) / MAX_POINTS);
  // Snap to a reasonable step.
  const steps = [60, 300, 900, 3600, 86400];
  bucketSec = steps.find((s) => s >= need) ?? 86400;
}

// Apply explicit bucket override last.
if (Number.isFinite(parsedBucketSec) && parsedBucketSec > 0) {
  const steps = [60, 300, 900, 3600, 86400];
  const want = Math.max(60, Math.min(86400, Math.floor(parsedBucketSec)));
  bucketSec = steps.find((s) => s >= want) ?? 86400;
} else if (bucketToken && bucketMap[bucketToken]) {
  bucketSec = bucketMap[bucketToken];
}

msg.topic = `WITH b AS (
  SELECT
    (ts_epoch / ${bucketSec}) * ${bucketSec} AS bucket_epoch,
    MAX(ts_epoch) AS last_epoch,
    AVG(Power_kW) AS kw,
    AVG(Voltage_V) AS voltageV,
    AVG(Current_A) AS currentA,
    AVG(PowerFactor) AS pf
  FROM plc_samples
  WHERE ts_epoch >= ${sinceEpoch}
  GROUP BY bucket_epoch
)
SELECT
  strftime('%Y-%m-%dT%H:%M:00.000Z', datetime(last_epoch, 'unixepoch')) AS ts,
  COALESCE(kw, 0) AS kw,
  COALESCE(voltageV, 0) AS voltageV,
  COALESCE(currentA, 0) AS currentA,
  COALESCE(pf, 0) AS pf,
  0 AS kvar
FROM b
ORDER BY last_epoch ASC;`;

delete msg.payload;
return msg;

const v = msg.payload || {};
if (!msg.payload || typeof msg.payload !== 'object') return null;

const ts = new Date().toISOString();
const tsEpoch = Math.floor(Date.now() / 1000);

const toSql = (x) => {
  if (x === undefined || x === null || x === '') return 'NULL';
  const n = Number(x);
  if (Number.isFinite(n)) return String(n);
  return 'NULL';
};

// Accept BOTH shapes:
// - "small DB16" payload (Power_kW + Total_*_kWh)
// - "full Excel" payload (RIO* and Total_EnergyCon_* keys)

let totalPower = Number(v.Power_kW);
let totalEnergy = Number(v.Energy_kWh);
let voltage = v.Voltage_V;
let current = v.Current_A;
let pf = v.PowerFactor;

if (!Number.isFinite(totalPower) || !Number.isFinite(totalEnergy)) {
  const meterPrefixes = [
    'RIO1CM1_EMU4_1', 'RIO1CM1_EMU4_2',
    'RIO1CM2_EM6400_10', 'RIO1CM2_EM6400_11',
    'RIO2CM1_EMU4_1', 'RIO2CM1_EMU4_2', 'RIO2CM1_EMU4_3', 'RIO2CM1_EMU4_4',
    'RIO2CM1_EMU4_5', 'RIO2CM1_EMU4_6', 'RIO2CM1_EMU4_7', 'RIO2CM1_EMU4_8',
    'RIO2CM1_EMU4_9', 'RIO2CM1_EMU4_10', 'RIO2CM1_EMU4_11', 'RIO2CM1_EMU4_12',
    'RIO2CM2_EM6400_1', 'RIO2CM2_EM6400_2', 'RIO2CM2_EM6400_3',
    'RIO2CM2_EM6400_4', 'RIO2CM2_EM6400_5', 'RIO2CM2_EM6400_6',
    'RIO2_PAC3200_51', 'RIO2_PAC3200_53', 'RIO2_UMG508_52'
  ];
  let p = 0, e = 0;
  for (const m of meterPrefixes) {
    p += Number(v[m + '_Real_power']) || 0;
    e += Number(v[m + '_Real_energy']) || 0;
  }
  totalPower = p;
  totalEnergy = e;
  voltage = v.RIO1CM1_EMU4_1_Voltage_Lave;
  current = v.RIO1CM1_EMU4_1_Current_Ave;
  pf = v.RIO1CM1_EMU4_1_Power_factor;
}

const totals = {
  Total_CrackerLine1_kWh: v.Total_CrackerLine1_kWh ?? v.Total_EnergyCon_kwh_Cracker_Line_1,
  Total_CrackerLine2_kWh: v.Total_CrackerLine2_kWh ?? v.Total_EnergyCon_kwh_Cracker_Line_2,
  Total_PretzelLine_kWh: v.Total_PretzelLine_kWh ?? v.Total_EnergyCon_kwh_Pretzel_Line,
  Total_WaferLine1_kWh: v.Total_WaferLine1_kWh ?? v.Total_EnergyCon_kwh_Wafer_Line_1,
  Total_WaferLine2_kWh: v.Total_WaferLine2_kWh ?? v.Total_EnergyCon_kwh_Wafer_Line_2,
  Total_ChocoyChocoLine_kWh: v.Total_ChocoyChocoLine_kWh ?? v.Total_EnergyCon_kwh_Chooey_Choco_Line,
  Total_DynamiteLine_kWh: v.Total_DynamiteLine_kWh ?? v.Total_EnergyCon_kwh_Dynamite_Line,
  Total_XOLine_kWh: v.Total_XOLine_kWh ?? v.Total_EnergyCon_kwh_XO_Line,
  Total_MaxxLine_kWh: v.Total_MaxxLine_kWh ?? v.Total_EnergyCon_kwh_Maxx_Line,
  Total_MainLine_kWh: v.Total_MainLine_kWh ?? v.Total_EnergyCon_kwh_Main_Line,
  Total_UtilitiesJaguar_kWh: v.Total_UtilitiesJaguar_kWh ?? v.Total_EnergyCon_kwh_Utilities_Jaguar,
  Total_UtilitiesLighting_kWh: v.Total_UtilitiesLighting_kWh ?? v.Total_EnergyCon_kwh_Utilities_Lighting_Power_Panel
};

const sql = `INSERT INTO plc_samples (
  ts, ts_epoch, Power_kW, Energy_kWh, Voltage_V, Current_A, PowerFactor,
  Total_CrackerLine1_kWh, Total_CrackerLine2_kWh, Total_PretzelLine_kWh,
  Total_WaferLine1_kWh, Total_WaferLine2_kWh, Total_ChocoyChocoLine_kWh,
  Total_DynamiteLine_kWh, Total_XOLine_kWh, Total_MaxxLine_kWh,
  Total_MainLine_kWh, Total_UtilitiesJaguar_kWh, Total_UtilitiesLighting_kWh
) VALUES (
  '${ts}', ${tsEpoch},
  ${toSql(totalPower)}, ${toSql(totalEnergy)},
  ${toSql(voltage)},
  ${toSql(current)},
  ${toSql(pf)},
  ${toSql(totals.Total_CrackerLine1_kWh)},
  ${toSql(totals.Total_CrackerLine2_kWh)},
  ${toSql(totals.Total_PretzelLine_kWh)},
  ${toSql(totals.Total_WaferLine1_kWh)},
  ${toSql(totals.Total_WaferLine2_kWh)},
  ${toSql(totals.Total_ChocoyChocoLine_kWh)},
  ${toSql(totals.Total_DynamiteLine_kWh)},
  ${toSql(totals.Total_XOLine_kWh)},
  ${toSql(totals.Total_MaxxLine_kWh)},
  ${toSql(totals.Total_MainLine_kWh)},
  ${toSql(totals.Total_UtilitiesJaguar_kWh)},
  ${toSql(totals.Total_UtilitiesLighting_kWh)}
);`;

msg.topic = sql;
delete msg.payload;
return msg;

global.set('plcSnapshot', {
  ts: new Date().toISOString(),
  values: msg.payload
});
return null;

const snap = global.get('plcSnapshot');
msg.payload = snap || {
  ts: new Date().toISOString(),
  values: null,
  warning: 'No S7 data received yet — check PLC IP, rack/slot, DB addresses, and TIA PUT/GET.'
};
msg.headers = { 'Content-Type': 'application/json; charset=utf-8' };
return msg;

const arr = global.get('enhancedAlerts') || [];
msg.payload = arr;
msg.headers = { 'Content-Type': 'application/json; charset=utf-8' };
return msg;

const id = msg.req?.params?.id;
const who = msg.req?.query?.by ?? 'user';
const arr = global.get('enhancedAlerts') || [];
const a = arr.find((x) => x.id === id);
if (a) {
  a.status = 'acknowledged';
  a.acknowledgedAt = new Date().toISOString();
  a.acknowledgedBy = String(who);
}
try {
  const fs = global.get('fs');
  const p = global.get('alertsArchivePath');
  if (fs && p) fs.writeFileSync(p, JSON.stringify(global.get('enhancedAlerts') || [], null, 2), 'utf8');
} catch (e) {}
msg.payload = a || null;
msg.headers = { 'Content-Type': 'application/json; charset=utf-8' };
return msg;

const id = msg.req?.params?.id;
const arr = global.get('enhancedAlerts') || [];
const a = arr.find((x) => x.id === id);
if (a) {
  a.status = 'resolved';
  a.resolvedAt = new Date().toISOString();
}
try {
  const fs = global.get('fs');
  const p = global.get('alertsArchivePath');
  if (fs && p) fs.writeFileSync(p, JSON.stringify(global.get('enhancedAlerts') || [], null, 2), 'utf8');
} catch (e) {}
msg.payload = a || null;
msg.headers = { 'Content-Type': 'application/json; charset=utf-8' };
return msg;

const id = msg.req?.params?.id;
const note = msg.req?.query?.note ?? '';
const arr = global.get('enhancedAlerts') || [];
const a = arr.find((x) => x.id === id);
if (a) {
  if (!Array.isArray(a.notes)) a.notes = [];
  if (note) a.notes.unshift(String(note));
}
try {
  const fs = global.get('fs');
  const p = global.get('alertsArchivePath');
  if (fs && p) fs.writeFileSync(p, JSON.stringify(global.get('enhancedAlerts') || [], null, 2), 'utf8');
} catch (e) {}
msg.payload = a || null;
msg.headers = { 'Content-Type': 'application/json; charset=utf-8' };
return msg;

const now = Date.now();
const snap = global.get('plcSnapshot');
const lastSample = global.get('plcLastSampleTs');

let lastPlcCommTs = null;
if (typeof lastSample === 'string') lastPlcCommTs = lastSample;
else if (snap?.ts) lastPlcCommTs = snap.ts;

let plcLinkUp = false;
if (lastPlcCommTs) {
  const t = Date.parse(lastPlcCommTs);
  if (Number.isFinite(t)) plcLinkUp = (now - t) <= 15000;
}

// Record PLC link transitions into Enhanced Alerts (/api/alarms)
const prevUp = global.get('plcLinkUpPrev');
if (prevUp === undefined) {
  global.set('plcLinkUpPrev', plcLinkUp);
} else if (prevUp !== plcLinkUp) {
  global.set('plcLinkUpPrev', plcLinkUp);

  const alerts = global.get('enhancedAlerts') || [];
  const ts = new Date().toISOString();
  const id = `plc-${ts}-${Math.random().toString(16).slice(2, 8)}`;
  const severity = plcLinkUp ? 'info' : 'critical';
  const priority = plcLinkUp ? 'low' : 'urgent';
  const message = plcLinkUp ? 'PLC link restored' : 'PLC link disconnected';
  const detail = plcLinkUp
    ? `PLC communication resumed at ${ts}.`
    : `No PLC communication within 15s. Last communication: ${lastPlcCommTs || 'unknown'}.`;

  alerts.unshift({
    id,
    meterId: 'plc',
    meterName: 'PLC Link',
    severity,
    priority,
    category: 'communication',
    status: 'active',
    message,
    detail,
    ts,
    acknowledgedAt: null,
    acknowledgedBy: null,
    resolvedAt: null,
    notes: [],
    incidentId: null
  });
  while (alerts.length > 500) alerts.pop();
  global.set('enhancedAlerts', alerts);
}

msg.payload = {
  ok: true,
  service: 'node-red',
  ts: new Date().toISOString(),
  plcLink: {
    up: plcLinkUp,
    lastCommunicationTs: lastPlcCommTs
  }
};
msg.headers = { 'Content-Type': 'application/json; charset=utf-8' };
return msg;

global.set('plcFullSnapshot', {
  ts: new Date().toISOString(),
  values: msg.payload
});
return null;

const snap = global.get('plcFullSnapshot');
msg.payload = snap || {
  ts: new Date().toISOString(),
  values: null,
  warning: 'No full S7 data received yet — check PLC connection and DB16 access.'
};
msg.headers = { 'Content-Type': 'application/json; charset=utf-8' };
return msg;

const v = msg.payload || {};
if (!msg.payload || typeof msg.payload !== 'object') return null;

// Throttle: once per 30 seconds
const now = Date.now();
const lastMs = global.get('meterSampleLastMs') || 0;
if (now - lastMs < 30000) return null;
global.set('meterSampleLastMs', now);

const ts = new Date().toISOString();
const tsEpoch = Math.floor(now / 1000);

const toSql = (x) => {
  if (x === undefined || x === null || x === '') return 'NULL';
  const n = Number(x);
  if (Number.isFinite(n)) return String(n);
  return 'NULL';
};

const meters = [
  'RIO1CM1_EMU4_1', 'RIO1CM1_EMU4_2',
  'RIO1CM2_EM6400_10', 'RIO1CM2_EM6400_11',
  'RIO2CM1_EMU4_1', 'RIO2CM1_EMU4_2', 'RIO2CM1_EMU4_3', 'RIO2CM1_EMU4_4',
  'RIO2CM1_EMU4_5', 'RIO2CM1_EMU4_6', 'RIO2CM1_EMU4_7', 'RIO2CM1_EMU4_8',
  'RIO2CM1_EMU4_9', 'RIO2CM1_EMU4_10', 'RIO2CM1_EMU4_11', 'RIO2CM1_EMU4_12',
  'RIO2CM2_EM6400_1', 'RIO2CM2_EM6400_2', 'RIO2CM2_EM6400_3',
  'RIO2CM2_EM6400_4', 'RIO2CM2_EM6400_5', 'RIO2CM2_EM6400_6',
  'RIO2_PAC3200_51', 'RIO2_PAC3200_53', 'RIO2_UMG508_52'
];

const params = [
  'Real_power', 'Reactive_power', 'Apparent_power',
  'Real_energy', 'Reactive_energy', 'Apparent_energy',
  'Voltage_ab', 'Voltage_bc', 'Voltage_ca', 'Voltage_Lave',
  'Voltage_an', 'Voltage_bn', 'Voltage_cn', 'Voltage_Nave',
  'Current_a', 'Current_b', 'Current_c', 'Current_Ave',
  'Power_factor', 'Frequency'
];

const cols = [
  'real_power_kw', 'reactive_power_kvar', 'apparent_power_kva',
  'real_energy_kwh', 'reactive_energy_kvarh', 'apparent_energy_kvah',
  'voltage_ab', 'voltage_bc', 'voltage_ca', 'voltage_ll_avg',
  'voltage_an', 'voltage_bn', 'voltage_cn', 'voltage_ln_avg',
  'current_a', 'current_b', 'current_c', 'current_avg',
  'power_factor', 'frequency'
];

const rows = [];
for (const m of meters) {
  const vals = params.map(p => toSql(v[m + '_' + p]));
  rows.push("('" + ts + "', " + tsEpoch + ", '" + m + "', " + vals.join(', ') + ")");
}

const sql = 'INSERT INTO meter_samples (ts, ts_epoch, meter_id, ' +
  cols.join(', ') + ') VALUES\n' + rows.join(',\n') + ';';

msg.topic = sql;
delete msg.payload;
return msg;

const v = msg.payload || {};
if (!msg.payload || typeof msg.payload !== 'object') return null;

const now = Date.now();
const toNum = (x) => {
  const n = typeof x === 'number' ? x : Number(x);
  return Number.isFinite(n) ? n : 0;
};

// --- Read total plant kW (same logic as existing insert node) ---
let totalKw = toNum(v.Power_kW);
if (!Number.isFinite(totalKw) || totalKw <= 0) {
  const meters = [
    'RIO1CM1_EMU4_1','RIO1CM1_EMU4_2',
    'RIO1CM2_EM6400_10','RIO1CM2_EM6400_11',
    'RIO2CM1_EMU4_1','RIO2CM1_EMU4_2','RIO2CM1_EMU4_3','RIO2CM1_EMU4_4',
    'RIO2CM1_EMU4_5','RIO2CM1_EMU4_6','RIO2CM1_EMU4_7','RIO2CM1_EMU4_8',
    'RIO2CM1_EMU4_9','RIO2CM1_EMU4_10','RIO2CM1_EMU4_11','RIO2CM1_EMU4_12',
    'RIO2CM2_EM6400_1','RIO2CM2_EM6400_2','RIO2CM2_EM6400_3',
    'RIO2CM2_EM6400_4','RIO2CM2_EM6400_5','RIO2CM2_EM6400_6',
    'RIO2_PAC3200_51','RIO2_PAC3200_53','RIO2_UMG508_52'
  ];
  totalKw = 0;
  for (const m of meters) totalKw += toNum(v[m + '_Real_power']);
}

// --- Rolling 15-min window (900 seconds) ---
const WINDOW_MS = 15 * 60 * 1000;
const buf = global.get('demandBuf') || [];
buf.push({ t: now, kw: totalKw });

// Trim older than 15 min
while (buf.length > 0 && buf[0].t < now - WINDOW_MS) buf.shift();
global.set('demandBuf', buf);

// Current 15-min average demand
const avgKw = buf.length > 0
  ? buf.reduce((s, p) => s + p.kw, 0) / buf.length
  : totalKw;

// --- Monthly peak tracking ---
const currentMonth = new Date().toISOString().slice(0, 7); // "2026-03"
let state = global.get('demandState') || {};
if (state.month !== currentMonth) {
  // New month — reset
  state = { month: currentMonth, peakKw: 0, peakTs: null, thresholdKw: state.thresholdKw || 0 };
}

if (avgKw > state.peakKw) {
  state.peakKw = avgKw;
  state.peakTs = new Date().toISOString();
}

// Default threshold: 110% of first observed peak (auto-calibrating)
if (state.thresholdKw <= 0 && state.peakKw > 0) {
  state.thresholdKw = Math.ceil(state.peakKw * 1.1);
}

const threshold = state.thresholdKw || 0;
const pctOfThreshold = threshold > 0 ? (avgKw / threshold) : 0;

global.set('demandState', state);

// --- Generate alerts at 80% and 95% of threshold ---
const lastAlertLevel = global.get('demandAlertLevel') || 0;
let newLevel = 0;
if (pctOfThreshold >= 0.95) newLevel = 2;
else if (pctOfThreshold >= 0.80) newLevel = 1;

if (newLevel > lastAlertLevel) {
  global.set('demandAlertLevel', newLevel);

  const alerts = global.get('enhancedAlerts') || [];
  const ts = new Date().toISOString();
  const id = 'demand-' + ts + '-' + Math.random().toString(16).slice(2, 8);
  const severity = newLevel === 2 ? 'critical' : 'warning';
  const priority = newLevel === 2 ? 'urgent' : 'high';
  const pctStr = (pctOfThreshold * 100).toFixed(0);
  const message = newLevel === 2
    ? 'Demand at ' + pctStr + '% of threshold — shed load NOW'
    : 'Demand approaching threshold (' + pctStr + '%)';
  const detail = 'Current 15-min avg: ' + avgKw.toFixed(1) + ' kW. Threshold: '
    + threshold.toFixed(0) + ' kW. Monthly peak: ' + state.peakKw.toFixed(1) + ' kW.';

  alerts.unshift({
    id,
    meterId: 'plant',
    meterName: 'Plant Demand',
    severity,
    priority,
    category: 'energy',
    status: 'active',
    message,
    detail,
    ts,
    acknowledgedAt: null,
    acknowledgedBy: null,
    resolvedAt: null,
    notes: [],
    incidentId: null
  });
  while (alerts.length > 500) alerts.pop();
  global.set('enhancedAlerts', alerts);
}

// Reset alert level when demand drops below 75%
if (pctOfThreshold < 0.75 && lastAlertLevel > 0) {
  global.set('demandAlertLevel', 0);
}

const insertEveryMs = 60_000;
const lastIns = global.get('demandSampleLastMs') || 0;
if (now - lastIns >= insertEveryMs) {
  global.set('demandSampleLastMs', now);
  const ts = new Date().toISOString().replace(/'/g, "''");
  const tsEpoch = Math.floor(now / 1000);
  msg.topic = `INSERT INTO demand_samples (ts, ts_epoch, current_demand_kw, instant_kw) VALUES ('${ts}', ${tsEpoch}, ${Number(avgKw)}, ${Number(totalKw)});`;
  return msg;
}
return null;

const state = global.get('demandState') || {};
const buf = global.get('demandBuf') || [];

const setTh = Number(msg.req?.query?.setThreshold);
if (Number.isFinite(setTh) && setTh > 0) {
  state.thresholdKw = setTh;
  global.set('demandState', state);
}

const currentKw = buf.length > 0
  ? buf.reduce((s, p) => s + p.kw, 0) / buf.length
  : 0;

const instantKw = buf.length > 0 ? buf[buf.length - 1].kw : 0;

const threshold = state.thresholdKw || 0;
const pctOfThreshold = threshold > 0 ? currentKw / threshold : 0;

const minutesParam = msg.req?.query?.minutes;
const allHistory = !minutesParam || minutesParam === 'all' || minutesParam === '';
let minutes = allHistory ? (60 * 24 * 366 * 5) : Math.max(15, Math.min(60 * 24 * 800, Number(minutesParam)));
const sinceEpoch = allHistory ? 0 : Math.floor(Date.now() / 1000) - Math.floor(minutes * 60);

let bucketSec = 60;
if (minutes > 60 * 24 * 90) bucketSec = 3600;
else if (minutes > 60 * 24 * 30) bucketSec = 900;
else if (minutes > 60 * 24 * 7) bucketSec = 300;

msg._demandMeta = {
  ts: new Date().toISOString(),
  month: state.month || new Date().toISOString().slice(0, 7),
  instantKw,
  currentDemandKw: Math.round(currentKw * 10) / 10,
  monthlyPeakKw: Math.round((state.peakKw || 0) * 10) / 10,
  monthlyPeakTs: state.peakTs || null,
  thresholdKw: threshold,
  pctOfThreshold: Math.round(pctOfThreshold * 1000) / 10,
  windowSeconds: 900,
  samplesInWindow: buf.length,
  allHistory
};

msg.topic = `WITH b AS (
  SELECT
    (ts_epoch / ${bucketSec}) * ${bucketSec} AS bucket_epoch,
    MAX(ts_epoch) AS last_epoch,
    AVG(current_demand_kw) AS kw
  FROM demand_samples
  WHERE ts_epoch >= ${sinceEpoch}
  GROUP BY bucket_epoch
)
SELECT
  strftime('%Y-%m-%dT%H:%M:%SZ', datetime(last_epoch, 'unixepoch')) AS ts,
  COALESCE(kw, 0) AS current_demand_kw
FROM b
ORDER BY last_epoch ASC
LIMIT 200000;`;

delete msg.payload;
return msg;

const meta = msg._demandMeta || {};
const rows = Array.isArray(msg.payload) ? msg.payload : [];

let trend = rows.map((r) => ({
  ts: r.ts,
  kw: Number(r.current_demand_kw) || 0
}));

const nowIso = meta.ts;
const curKw = meta.currentDemandKw;
const lastTs = trend.length > 0 ? Date.parse(trend[trend.length - 1].ts) : NaN;
if (trend.length === 0 || !Number.isFinite(lastTs) || Date.parse(nowIso) > lastTs + 25000) {
  trend = trend.concat([{ ts: nowIso, kw: curKw }]);
}

const trendStartTs = trend.length > 0 ? trend[0].ts : null;

msg.payload = {
  ts: meta.ts,
  month: meta.month,
  instantKw: meta.instantKw,
  currentDemandKw: meta.currentDemandKw,
  monthlyPeakKw: meta.monthlyPeakKw,
  monthlyPeakTs: meta.monthlyPeakTs,
  thresholdKw: meta.thresholdKw,
  pctOfThreshold: meta.pctOfThreshold,
  windowSeconds: meta.windowSeconds,
  samplesInWindow: meta.samplesInWindow,
  trend,
  trendStartTs
};

msg.headers = { 'Content-Type': 'application/json; charset=utf-8' };
delete msg._demandMeta;
return msg;

const p = msg.payload;
if (!p || typeof p !== 'object') {
    return [ { payload: 'Waiting for PLC…' }, null, null, null ];
}
const r0 = Number(p.DB1_REAL0);
const r4 = Number(p.DB1_REAL4);
const r8 = Number(p.DB1_REAL8);
const line = (k, v) => `${k}: ${Number.isFinite(v) ? v.toFixed(3) : '—'}`;
const text = [
  line('DB1,REAL0', r0),
  line('DB1,REAL4', r4),
  line('DB1,REAL8', r8)
].join('\n');
return [
  { payload: text },
  { payload: r0 },
  { payload: r4 },
  { payload: r8 }
];

msg.topic = `SELECT id, ts, ts_epoch, payload FROM enhanced_alerts ORDER BY ts_epoch DESC LIMIT 2000`;
delete msg.payload;
return msg;

const fs = global.get('fs');
const archivePath = global.get('alertsArchivePath');
let fromFile = [];
if (archivePath && fs) {
  try {
    const raw = fs.readFileSync(archivePath, 'utf8');
    const parsed = JSON.parse(raw);
    if (Array.isArray(parsed)) fromFile = parsed.filter((a) => a && a.id);
  } catch (e) {}
}
const rows = Array.isArray(msg.payload) ? msg.payload : [];
const fromDb = [];
for (const r of rows) {
  try {
    const o = JSON.parse(r.payload);
    if (o && o.id) fromDb.push(o);
  } catch (e) {}
}
const mem = global.get('enhancedAlerts') || [];
const byId = new Map();
const tsOf = (a) => Date.parse(a.ts || '') || 0;
for (const a of fromDb) byId.set(a.id, a);
for (const a of fromFile) {
  const ex = byId.get(a.id);
  if (!ex || tsOf(a) >= tsOf(ex)) byId.set(a.id, a);
}
for (const a of mem) {
  if (!byId.has(a.id)) byId.set(a.id, a);
}
const merged = Array.from(byId.values()).sort((a, b) => tsOf(b) - tsOf(a));
while (merged.length > 2000) merged.pop();
global.set('enhancedAlerts', merged);
return null;

const arr = global.get('enhancedAlerts') || [];
if (arr.length === 0) return null;
const esc = (s) => String(s).replace(/'/g, "''");
const batchSize = 40;
const msgs = [];
for (let i = 0; i < arr.length; i += batchSize) {
  const part = arr.slice(i, i + batchSize);
  const vals = part.map((a) => {
    const ts = a.ts || new Date().toISOString();
    const te = Math.floor(Date.parse(ts) / 1000) || 0;
    const p = esc(JSON.stringify(a));
    return `('${esc(a.id)}', '${esc(ts)}', ${te}, '${p}')`;
  });
  msgs.push({
    topic: `INSERT OR REPLACE INTO enhanced_alerts (id, ts, ts_epoch, payload) VALUES ${vals.join(',')};`,
    payload: null
  });
}
return msgs;

const fs = global.get('fs');
const archivePath = global.get('alertsArchivePath');
if (!fs || !archivePath) return null;
const arr = global.get('enhancedAlerts') || [];
try {
  fs.writeFileSync(archivePath, JSON.stringify(arr, null, 2), 'utf8');
} catch (e) {
  node.warn('enhanced_alerts_archive.json write failed: ' + (e && e.message));
}
return null;
